import React, { useMemo, useEffect, useRef, useState } from "react";
import { Helmet } from 'react-helmet-async';
import { HelmetProvider } from 'react-helmet-async';
import data from "./data/portfolio.json";
const rawItems = data.items;
const { temas, tags, usos } = data.dicts;
const items = rawItems.map((item) => {
  const temasLabels = item.meta.temas.map((i) => temas[i]);
  const tagsLabels = item.meta.tags.map((i) => tags[i]);
  const usosLabels = item.meta.usos.map((i) => usos[i]);

  const allFilters = [...temasLabels, ...tagsLabels, ...usosLabels];
  const allFiltersLower = allFilters.map(f => f.toLowerCase());

  // Corregir categoría: mapear "otros" según el prefijo del ID
  let categoria = item.categoria;
  if (categoria === "otros") {
    if (item.id.startsWith("ilu-")) {
      categoria = "ilustracion";
    } else if (item.id.startsWith("dis-")) {
      categoria = "diseno";
    }
  }

  return {
    ...item,
    categoria, // ← Sobreescribimos con la categoría corregida
    temasLabels,
    tagsLabels,
    usosLabels,
    allFilters,
    allFiltersLower,
  };
});
const getImage = (item, type) => {
  const ext = "png";
  return `/${item.categoria}/${type}/${item.id}${
    type === "thumb" ? "-thumb" : ""
  }.${ext}`;
};
function useClickOutside(ref, callback) {
  useEffect(() => {
    const handle = (e) => {
      if (ref.current && !ref.current.contains(e.target)) callback();
    };
    document.addEventListener("mousedown", handle);
    return () => document.removeEventListener("mousedown", handle);
  }, [ref, callback]);
}

/* =========================
   1) UTILIDADES
========================= */
const chipBase = {
  padding: "7px 11px",
  borderRadius: "999px",
  border: "1px solid #d0d0d0",
  background: "#fff",
  color: "#111",
  cursor: "pointer",
  fontSize: "13px",
  lineHeight: 1,
};
const groupBtn = {
  width: "100%",
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  padding: "10px 12px",
  borderRadius: "99px",
  border: "1px solid rgba(120,80,200,0.5)",
  background: "#fff",
  cursor: "pointer",
  fontWeight: "normal",
};
const gridCardBase = {
  all: "unset",
  display: "block",
  cursor: "pointer",
  width: "100%",
  borderRadius: "12px",
  overflow: "hidden",
  background: "#fff",
  transition: "all 0.25s ease",
};
const useInView = (ref) => {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    if (!("IntersectionObserver" in window)) {
      setVisible(true);
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setVisible(true);
            observer.unobserve(el);
          }
        });
      },
      {
        rootMargin: "150px 0px",
        threshold: 0.01,
      }
    );

    observer.observe(el);

    return () => {
      observer.unobserve(el); // ✅ también aquí
      observer.disconnect();
    };
  }, [ref]);

  return visible;
};
function LazyImage({ src, alt, style }) {
  const ref = useRef();
  const visible = useInView(ref);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    setLoaded(false);
  }, [src]);
  return (
    <img
      ref={ref}
      src={visible ? src : "/placeholder.jpg"}
      alt={alt}
      decoding="async"
      onLoad={() => setLoaded(true)}
      style={{
        ...style,
        opacity: visible ? 1 : 0.3,
        transition: "opacity 0.4s ease",
      }}
    />
  );
}
const GridItem = React.memo(function GridItem({
  item,
  selectedId,
  hoveredId,
  setHovered,
  changeSelected,
  isSingle,
}) {
  return (
    <button
      type="button"
      onClick={() => changeSelected(item)}
      aria-label={`Ver ${item.titulo}`}
      onMouseEnter={() => setHovered(item.id)}
      onMouseLeave={() => setHovered(null)}
      style={{
        ...gridCardBase,
        border: selectedId === item.id ? "2px solid #666" : "1px solid #e5e5e5",
        transform: hoveredId === item.id ? "translateY(-6px)" : "translateY(0)",
        boxShadow:
          hoveredId === item.id
            ? "0 8px 18px rgba(0,0,0,0.12)"
            : "0 1px 4px rgba(0,0,0,0.04)",
        maxWidth: isSingle ? "clamp(300px, 50vw, 500px)" : "100%",
      }}
    >
      <div
        style={{
          width: "100%",
          height: "200px",
          overflow: "hidden",
          borderTopLeftRadius: "12px",
          borderTopRightRadius: "12px",
          background: "#f5f5f5",
          position: "relative",
        }}
      >
        <LazyImage
  src={getImage(item, "thumb")}
  alt={item.titulo}
  style={{
    width: "100%",
    height: "100%",
    objectFit: "cover",
    objectPosition: "top",
    position: "absolute",
    top: 0,
    left: 0,
  }}
/>
      </div>
      <div style={{ padding: "10px" }}>
        <div style={{ fontWeight: "bold" }}>{item.titulo}</div>
        <div style={{ fontSize: "12px", color: "#666" }}>
          {item.descripcion}
        </div>
      </div>
    </button>
  );
});
/* =========================
   2) COMPONENTE
========================= */
export default function Portfolio() {
  const [query, setQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("todas");
  const [activeFilters, setActiveFilters] = useState([]);
  const [selected, setSelected] = useState(null);
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const filtersContainerRef = useRef(null);
  useClickOutside(filtersContainerRef, () => setFiltersOpen(false));
  const [openGroup, setOpenGroup] = useState(null);
  const [hovered, setHovered] = useState(null);
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [zoom, setZoom] = useState(false);
  const [fade, setFade] = useState(true);
  const [openPanel, setOpenPanel] = useState(null); // "left" | "right" | null
  const [hoveredPanel, setHoveredPanel] = useState(null);
  const [sent, setSent] = useState(false);
  const [gridFade, setGridFade] = useState(true);
  const [page, setPage] = useState(1);
  const pageSize = 24;
  const [loading, setLoading] = useState(false);
  useEffect(() => {
    if (sent) {
      const t = setTimeout(() => setSent(false), 4000);
      return () => clearTimeout(t);
