            gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
            justifyItems: "center",
            gap: "16px",
            gridAutoRows: "auto",
            opacity: gridFade ? 1 : 0,
            transition: "opacity 0.3s ease",
            minHeight: filtered.length === 0 ? "200px" : "auto",
          }}
        >
          {filtered.length === 0 && (
            <div
              style={{
                gridColumn: "1 / -1",
                textAlign: "center",
                color: "white",
                fontSize: "16px",
                padding: "40px 0",
                fontStyle: "italic",
              }}
            >
              Sin resultados. Prueba a modificar búsqueda o filtros.
            </div>
          )}
          {paginated.map((item) => (
            <GridItem
              key={item.id}
              item={item}
              selectedId={pageSelected?.id}
              hoveredId={hovered}
              setHovered={setHovered}
              changeSelected={changeSelected}
              isSingle={isSingle}
            />
          ))}
        </div>
        {lightboxOpen && selected && (
  <div
    ref={lightboxRef}
    role="dialog"
    aria-modal="true"
    aria-label={`Vista ampliada de ${selected.titulo}`}
    tabIndex={-1}
    onClick={(e) => {
      if (isSwiping.current) return;
      setZoom(false);
      setTimeout(() => {
        setLightboxOpen(false);
        setSelected(null);
      }, 200);
    }}
    onTouchStart={(e) => {
      isSwiping.current = false;
      touchStartX.current = e.touches[0].clientX;
    }}
    onTouchMove={(e) => {
      touchEndX.current = e.touches[0].clientX;
      if (Math.abs(touchStartX.current - touchEndX.current) > 10) {
        isSwiping.current = true;
      }
    }}
    onTouchEnd={() => {
      const diff = touchStartX.current - touchEndX.current;
      if (diff > 40) goNext();
      if (diff < -40) goPrev();
    }}
    style={{
      position: "fixed",
      inset: 0,
      background: "rgba(0,0,0,0.95)",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      zIndex: 999,
    }}
  >
    {/* IMAGEN + FLECHAS */}
    <div style={{
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      width: "100%",
      flex: 1,
      minHeight: 0,
    }}>
      {/* Flecha izquierda */}
      <button
        type="button"
        onClick={(e) => { e.stopPropagation(); goPrev(); }}
        aria-label="Imagen anterior"
        style={{
          position: "absolute",
          left: 0,
          top: isMobile ? "33%" : 0,
          bottom: isMobile ? "33%" : 0,
          width: isMobile ? "20%" : "15%",
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-start",
          paddingLeft: "15px",
          fontSize: "clamp(30px, 5vw, 50px)",
          color: "rgba(255,255,255,0.8)",
          cursor: "pointer",
          background: "transparent",
          border: "none",
          zIndex: 2,
        }}
      >
        ‹
      </button>

      {/* Imagen */}
      <img
        src={getImage(selected, "full")}
        alt={selected.titulo}
        loading="eager"
        draggable="true"
        onClick={(e) => e.stopPropagation()}
        style={{
          maxWidth: isMobile ? "85%" : "75%",
          maxHeight: "80vh",
          borderRadius: "12px",
          boxShadow: "0 20px 60px rgba(0,0,0,0.5)",
          transform: zoom ? "scale(1)" : "scale(0.85)",
          opacity: zoom ? 1 : 0,
          transition: "all 0.3s ease",
          cursor: "default",
          objectFit: "contain",
        }}
      />

      {/* Flecha derecha */}
      <button
        type="button"
        onClick={(e) => { e.stopPropagation(); goNext(); }}
        aria-label="Siguiente imagen"
        style={{
          position: "absolute",
          right: 0,
          top: isMobile ? "33%" : 0,
          bottom: isMobile ? "33%" : 0,
          width: isMobile ? "20%" : "15%",
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-end",
          paddingRight: "15px",
          fontSize: "clamp(30px, 5vw, 50px)",
          color: "rgba(255,255,255,0.8)",
          cursor: "pointer",
          background: "transparent",
          border: "none",
          zIndex: 2,
        }}
      >
        ›
      </button>
    </div>

    {/* INFO + DESCARGA (barra inferior) */}
    <div style={{
      width: "100%",
      padding: "16px 20px",
      background: "rgba(0,0,0,0.8)",
      color: "#fff",
      textAlign: "center",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      gap: "6px",
    }}>
      <h3 style={{ margin: 0, fontSize: "clamp(14px, 2vw, 18px)", fontWeight: "600" }}>
        {selected.titulo}
      </h3>
      <p style={{ margin: 0, fontSize: "clamp(11px, 1.5vw, 14px)", opacity: 0.7 }}>
        {selected.descripcion}
        {(selected.creditos?.origen || selected.creditos?.basado_en) && (
          <span style={{ opacity: 0.6, fontSize: "clamp(10px, 1.2vw, 12px)" }}>
            {" · "}
            {selected.creditos?.origen && selected.creditos.origen}
            {selected.creditos?.origen && selected.creditos?.basado_en && " · "}
            {selected.creditos?.basado_en && `De: ${selected.creditos.basado_en}`}
          </span>
        )}
      </p>
      <a
        href={getImage(selected, "full")}
        download={`${selected.titulo}.png`}
        onClick={(e) => e.stopPropagation()}
        style={{
          padding: "8px 20px",
          borderRadius: "8px",
          border: "1px solid rgba(255,255,255,0.4)",
          color: "#fff",
          fontSize: "13px",
          textDecoration: "none",
          cursor: "pointer",
          transition: "all 0.2s ease",
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = "rgba(255,255,255,0.15)";
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = "transparent";
        }}
      >
        ⬇ Descargar
      </a>
    </div>
  </div>
)}
        {/* PAGINACIÓN */}
{filtered.length > pageSize && (
  <div style={{
    textAlign: "center",
    margin: "24px 0",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    gap: "16px",
  }}>
    <button
      type="button"
      onClick={() => setPage((p) => p - 1)}
      disabled={page === 1}
      style={{
        background: page === 1 ? "rgba(255,255,255,0.15)" : "rgba(255,255,255,0.25)",
        color: page === 1 ? "rgba(255,255,255,0.3)" : "#fff",
        border: "1px solid rgba(255,255,255,0.2)",
        borderRadius: "50%",
        width: "40px",
        height: "40px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: page === 1 ? "default" : "pointer",
        fontSize: "18px",
        transition: "all 0.2s ease",
      }}
    >
      ←
    </button>

    <span style={{
      color: "rgba(255,255,255,0.7)",
      fontSize: "14px",
      minWidth: "100px",
    }}>
      {page} de {Math.ceil(filtered.length / pageSize)}
    </span>

    <button
      type="button"
      onClick={() => setPage((p) => p + 1)}
      disabled={page * pageSize >= filtered.length}
      style={{
        background: page * pageSize >= filtered.length ? "rgba(255,255,255,0.15)" : "rgba(255,255,255,0.25)",
        color: page * pageSize >= filtered.length ? "rgba(255,255,255,0.3)" : "#fff",
        border: "1px solid rgba(255,255,255,0.2)",
        borderRadius: "50%",
        width: "40px",
        height: "40px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: page * pageSize >= filtered.length ? "default" : "pointer",
        fontSize: "18px",
        transition: "all 0.2s ease",
      }}
    >
      →
    </button>
  </div>
)}
        {/* INFOPANELS */}
        <div
          id="info-panels"
          ref={panelsRef}
          style={{
            background: "rgb(79, 103, 125)",
            padding: "24px 20px 28px",
            marginTop: "20px",
            marginBottom: "0",
          }}
        >
          {/* los dos paneles */}
          <div
            style={{
              display: "flex",
              flexWrap: "wrap",
              gap: "30px",
              alignItems: "flex-start",
              justifyContent: "center",
              maxWidth: "1200px",
              margin: "0 auto",
            }}
          >
            {/* IZQUIERDA */}
            <div
              onClick={() => setOpenPanel(openPanel === "left" ? null : "left")}
              onMouseEnter={() => setHoveredPanel("left")}
              onMouseLeave={() => setHoveredPanel(null)}
              style={{
                flex: "1 1 360px",
                minWidth: "280px",
                background: "#fff",
                borderRadius: "18px",
                overflow: "hidden",
                cursor: "pointer",
                transition:
                  "transform 0.2s ease, box-shadow 0.2s ease, min-height 0.3s ease",
                height: openPanel === "left" ? "auto" : "110px",
                boxShadow:
                  hoveredPanel === "left"
                    ? "0 12px 28px rgba(0,0,0,0.18)"
                    : "0 6px 18px rgba(0,0,0,0.12)",
                transform:
                  hoveredPanel === "left" ? "scale(1.015)" : "scale(1)",
                display: "flex",
                flexDirection: "column",
              }}
            >
              <div
                style={{
                  padding: "16px 20px 6px",
                  fontFamily: "Montserrat, sans-serif",
                  fontStyle: "italic",
                  color: "#555",
                  fontSize: "20px",
                  lineHeight: 1.1,
                  flexShrink: 0,
                }}
              >
                Presentación y Nota Legal
              </div>
              <div
                style={{
                  padding: "0 20px 20px",
                  color: "#666",
                  fontSize: "14px",
                  lineHeight: 1.4,
                  overflow: "hidden",
                  display: "-webkit-box",
                  WebkitLineClamp: openPanel === "left" ? "unset" : 3,
                  WebkitBoxOrient: "vertical",
                  overflow: "hidden",
                  position: "relative",

                  whiteSpace: "pre-line",
                  textAlign: "justify",
                  textAlignLast: "left",
                }}
              >
                {openPanel === "left" ? (
                  <>
                    {leftText.split("\n\n").map((p, i) => (
                      <p key={i} style={{ margin: "0 0 12px" }}>
                        {p}
                      </p>
                    ))}
                    <div
                      style={{
                        display: "flex",
                        justifyContent: "center",
                        marginTop: "16px",
                      }}
                    >
                      <a
                        href="/data/notaslegales.pdf"
                        target="_blank"
                        rel="noopener noreferrer"
                        onClick={(e) => e.stopPropagation()}
                        style={{
                          padding: "8px 16px",
                          borderRadius: "6px",
                          border: "1px solid #ccc",
                          background: "#fff",
                          color: "#444",
                          fontSize: "12px",
                          fontStyle: "italic",
                          textDecoration: "none",
                          cursor: "pointer",
                        }}
                      >
                        Aviso Legal
                      </a>
                    </div>
                  </>
                ) : (
                  <div style={{ position: "relative" }}>
                    <span style={{ display: "block" }}>{leftText}</span>
                    {/* degradado SOLO cuando está cerrado */}
                    <div
                      style={{
                        position: "absolute",
                        bottom: 0,
                        left: 0,
                        right: 0,
                        height: "40px",
                        background:
                          "linear-gradient(to bottom, rgba(255,255,255,0), rgba(255,255,255,0.9), rgba(255,255,255,1))",
                        pointerEvents: "none",
                      }}
                    />
                  </div>
                )}
              </div>
            </div>
            {/* DERECHA */}
            <div
              onClick={() =>
                setOpenPanel(openPanel === "right" ? null : "right")
              }
              onMouseEnter={() => setHoveredPanel("right")}
              onMouseLeave={() => setHoveredPanel(null)}
              style={{
                flex: "1 1 360px",
                minWidth: "280px",
                background: "#fff",
                borderRadius: "18px",
                overflow: "hidden",
                cursor: "pointer",
                transition:
                  "transform 0.2s ease, box-shadow 0.2s ease, min-height 0.3s ease",
                height: openPanel === "right" ? "auto" : "110px",
                boxShadow:
                  hoveredPanel === "right"
                    ? "0 12px 28px rgba(0,0,0,0.18)"
                    : "0 6px 18px rgba(0,0,0,0.12)",
                transform:
                  hoveredPanel === "right" ? "scale(1.015)" : "scale(1)",
                display: "flex",
                flexDirection: "column",
              }}
            >
              <div
                style={{
                  padding: "16px 20px 6px",
                  fontFamily: "Montserrat, sans-serif",
                  fontStyle: "italic",
                  color: "#555",
                  fontSize: "20px",
                  lineHeight: 1.1,
                  flexShrink: 0,
                }}
              >
                Consulta y Contacto
              </div>
              <div
                style={{
                  padding: "0 20px 20px",
                  color: "#666",
                  fontSize: "14px",
                  lineHeight: 1.4,
                  overflow: "hidden",
                  position: "relative",
                }}
              >
                {openPanel === "right" ? (
                  <>
                    <div style={{ marginTop: "18px" }}>
                      Si tienes cualquier duda, consulta o aportación, puedes
                      hacerlo desde aquí. Tus datos sólo se usarán para este
                      fin.
                    </div>

                    {/* FORMULARIO */}
                    <div
                      style={{
                        opacity: openPanel === "right" ? 1 : 0,
                        maxHeight: openPanel === "right" ? "500px" : "0px",
                        overflow: "hidden",
                        transition: "opacity 0.25s ease, max-height 0.3s ease",
                        pointerEvents: openPanel === "right" ? "auto" : "none",
                        marginTop: openPanel === "right" ? "12px" : "0px",
                      }}
                    >
                      <form
                        onSubmit={async (e) => {
                          e.preventDefault();
                          e.stopPropagation();

                          setLoading(true);

                          const formData = new FormData(e.target);

                          const res = await fetch(
                            "https://formspree.io/f/mnjlgkyw",
                            {
                              method: "POST",
                              body: formData,
                              headers: { Accept: "application/json" },
                            }
                          );

                          if (res.ok) {
                            setSent(true);
                            e.target.reset();
                          }

                          setLoading(false);
                        }}
                        onClick={(e) => e.stopPropagation()}
                        style={{
                          display: "flex",
                          flexDirection: "column",
                          gap: "8px",
                          maxWidth: "300px",
                        }}
                      >
                        <input
                          type="email"
                          name="email"
                          placeholder="Tu email"
                          required
                          style={{
                            padding: "8px 10px",
                            borderRadius: "6px",
                            border: "1px solid #ccc",
                            fontSize: "13px",
                            fontFamily: "Montserrat, sans-serif",
                            outline: "none",
                          }}
                          onFocus={(e) =>
                            (e.target.style.border = "1px solid #0b1f4d")
                          }
                          onBlur={(e) =>
                            (e.target.style.border = "1px solid #ccc")
                          }
                        />
                        <textarea
                          name="message"
                          placeholder="Mensaje"
                          required
                          rows={4}
                          style={{
                            padding: "8px 10px",
                            borderRadius: "6px",
                            border: "1px solid #ccc",
                            fontSize: "13px",
                            fontFamily: "Montserrat, sans-serif",
                            outline: "none",
                            resize: "vertical",
                          }}
                          onFocus={(e) =>
                            (e.target.style.border = "1px solid #0b1f4d")
                          }
                          onBlur={(e) =>
                            (e.target.style.border = "1px solid #ccc")
                          }
                        />
                        <button
                          type="submit"
                          disabled={loading}
                          style={{
                            padding: "8px 12px",
                            borderRadius: "6px",
                            border: "1px solid #ccc",
                            background: "#fff",
                            fontSize: "13px",
                            fontFamily: "Montserrat, sans-serif",
                            cursor: "pointer",
                            transition: "all 0.2s ease",
                          }}
                          onMouseEnter={(e) => {
                            e.currentTarget.style.background = "#f0f0f0";
                          }}
                          onMouseLeave={(e) => {
                            e.currentTarget.style.background = "#fff";
                          }}
                        >
                          {loading ? "Enviando..." : "Enviar"}
                        </button>
                        {sent && (
                          <div
                            role="status"
                            aria-live="polite"
                            style={{
                              marginTop: "10px",
                              fontSize: "12px",
                              color: "#0b1f4d",
                              fontStyle: "italic",
                            }}
                          >
                            ✔ Mensaje enviado correctamente
                          </div>
                        )}
                      </form>
                    </div>
                  </>
                ) : (
                  <div style={{ position: "relative" }}>
                    <span style={{ display: "block" }}>
                      Si tienes cualquier duda, consulta o aportación, puedes
                      hacerlo desde aquí. Tus datos sólo se usarán para este
                      fin.
                    </span>

                    {/* degradado */}
                    <div
                      style={{
                        position: "absolute",
                        bottom: 0,
                        left: 0,
                        right: 0,
                        height: "40px",
                        background:
                          "linear-gradient(to bottom, rgba(255,255,255,0), rgba(255,255,255,1))",
                        pointerEvents: "none",
                      }}
                    />
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
      <div
        style={{
          background: "#fff",
          padding: "16px 24px",
          display: "flex",
          alignItems: "left",
          justifyContent: "space-between",
          marginTop: "0px",
          fontFamily: "'Montserrat', sans-serif",
        }}
      >
        <div style={{ flex: 1 }}></div>
        <div
          style={{
            flex: 1,
            textAlign: "left",
            color: "#777",
            fontSize: "12px",
          }}
        >
          © AMP 2026
        </div>
        <img
          src="/logo.png"
          alt="Marist-Art"
          style={{
            height: "40px",
            objectFit: "contain",
            cursor: "pointer",
            opacity: 0.9,
            transition: "opacity 0.2s ease",
          }}
          onMouseEnter={(e) => (e.currentTarget.style.opacity = 1)}
          onMouseLeave={(e) => (e.currentTarget.style.opacity = 0.9)}
          onClick={() => {
            setQuery("");
            setSelectedCategory("todas");
            setActiveFilters([]);
          }}
        />
      </div>
    </div>
  </HelmetProvider>
);
}
